// 1. جلب البيانات من عقدة Set السابقة
const c = $('Set: Extract Incoming').first().json;

// 2. جلب مخرجات عقدة Redis
// ملاحظة: استبدل 'propertyName' بالاسم الفعلي للحقل الذي تخرج فيه بيانات Redis (مثل value أو data).
// إذا كانت البيانات تخرج مباشرة في الجذر الأساسي، سيلتقطها الكود تلقائياً ككائن بفضل الـ Fallback.
const raw = $input.first().json.propertyName ?? $input.first().json.value ?? $input.first().json;

let parsed = {};

// 3. التحقق الذكي: إذا كان نصاً قم بتحليله، وإذا كان كائناً خذه كما هو
if (typeof raw === 'string' && raw.trim() !== '') {
  try { 
    parsed = JSON.parse(raw); 
  } catch { 
    parsed = {}; 
  }
} else if (raw && typeof raw === 'object' && !Array.isArray(raw)) {
  parsed = raw;
}

// 4. استخراج القيم مع وضع قيم افتراضية آمنة في حال عدم وجودها
const status = parsed.status ? String(parsed.status) : 'None';
const account_key = parsed.account_key ? String(parsed.account_key) : '';
const fail_count = parsed.fail_count !== undefined ? Number(parsed.fail_count) : 0;

// 5. دمج المخرجات وإعادتها للعقدة التالية
return { 
  json: { 
    ...c, 
    status, 
    account_key, 
    fail_count: Number.isFinite(fail_count) ? fail_count : 0 
  } 
};

