// ==========================================
// 1. تحديد المنطقة الزمنية
// ==========================================
const phone = $input.first().json.phone || ""; 
let userTimeZone = 'UTC'; 
if (phone) {
  const cleanPhone = phone.replace(/[^\d+]/g, '');
  const tzMap = {
    '+966': 'Asia/Riyadh', '+971': 'Asia/Dubai', '+965': 'Asia/Kuwait',
    '+974': 'Asia/Qatar', '+973': 'Asia/Bahrain', '+968': 'Asia/Muscat',
    '+962': 'Asia/Amman', '+961': 'Asia/Beirut', '+963': 'Asia/Damascus',
    '+964': 'Asia/Baghdad', '+967': 'Asia/Aden', '+20': 'Africa/Cairo', 
    '+212': 'Africa/Casablanca', '+213': 'Africa/Algiers'
  };
  for (let i = 4; i >= 3; i--) {
    const prefix = cleanPhone.substring(0, i);
    if (tzMap[prefix]) { userTimeZone = tzMap[prefix]; break; }
  }
}

// أداة تنسيق التاريخ فقط (DD/MM/YYYY)
const dateFormatter = new Intl.DateTimeFormat('en-GB', { 
    timeZone: userTimeZone, 
    day: '2-digit', month: '2-digit', year: 'numeric'
});

// ==========================================
// 2. تجميع الرسائل وترتيبها
// ==========================================
let allMessages = [];
for (const item of items) {
    let pageMessages = item.json.payload || item.json.messages || (Array.isArray(item.json) ? item.json : []);
    allMessages = allMessages.concat(pageMessages);
}
allMessages.sort((a, b) => a.created_at - b.created_at);

// ==========================================
// 3. تحليل المحادثة ومعالجة البيانات
// ==========================================
let processedMessages = [];
let latestCustomerMessage = "";
let failCount = 0;
let successCount = 0;

allMessages.forEach(msg => {
    let text = msg.content ? msg.content.trim() : "";
    let hasAttachment = msg.attachments && msg.attachments.length > 0;

    // تخطي الرسائل المحذوفة والفارغة
    if (text === "تم حذف هذه الرسالة" || (!text && !hasAttachment)) return; 

    // حساب مرات النجاح والفشل من كامل المحادثة
    if (msg.message_type === 0) { 
        if (text.includes("جاني خطأ") || text.includes("خطأ - حد اقصى")) failCount++;
        if (text.includes("نعم✅") || text.includes("اشتغل") || text.includes("تمام")) successCount++;
    }

    let dateObj = new Date(msg.created_at * 1000);
    let msgDate = dateFormatter.format(dateObj); // المخرج: 28/02/2026

    // تحديد المرسل
    let sender = "U"; 
    if (msg.message_type === 0) {
        sender = "C"; // Customer
        latestCustomerMessage = text;
    } else if (msg.message_type === 1) {
        if (msg.content_attributes && msg.content_attributes.sent_by_ai === true) sender = "A"; // AI
        else if (msg.content_attributes && msg.content_attributes.sent_by_otp === true) sender = "Bot"; // OTP
        else sender = "H"; // Human
    } else if (msg.message_type === 2 || msg.message_type === 3) {
        sender = "S"; // System
    }

    // فلترة وضغط الرسائل الثابتة والروابط
    if (sender === "S" && text.includes("تم تحديث حالة المحادثة لـ\"مغلقة\"")) return; 

    if (text.includes("youtube.com/shorts/Z5gtTL-9UYg")) {
        text = "[Agent: Sent Disney+ instructional video & requested Email/Order No.]";
    }

    if (sender === "Bot") {
        if (text.includes("تمت معالجة طلبك بنجاح")) text = "[Bot: Started OTP Flow - Sent 3min warning]";
        else if (text.includes("الرجاء الرجوع إلى صفحة الطلب") || 
                 text.includes("ثم انتقل إلى تطبيق Disney+") || 
                 text.includes("هذه هي الصفحة التي ستقوم بإدخال الرمز") ||
                 text.includes("اظغط على هذا الزر اذا لم يصلك الرمز")) return; // حذف كامل
        else if (text.includes("هل قمت باتباع الخطوات؟")) text = "[Bot: Asked if ready (Options)]";
        else if (text.includes("ممتاز، سيصلك رمز التحقق قريبًا")) text = "[Bot: Warned to wait 20s]";
        else if (text.includes("عذراً، انتهى وقت الجلسة")) text = "[Bot: Session Timeout (3 mins passed)]";
        else if (text.includes("نعتذر عن ذلك 🙏. لقد حدثت مشكلة بسيطة")) text = "[Bot: 10-minute block applied due to max attempts]";
    }

    let optionsText = "";
    if (msg.content_attributes && msg.content_attributes.items) {
        let opts = msg.content_attributes.items.map(i => i.title || i.value).join(" | ");
        optionsText = ` (Options: ${opts})`;
    }

    if (hasAttachment && !text.includes("[Bot:") && !text.includes("[Agent:")) {
        text += " [Image Attached]";
    }

    // حفظ الرسالة مع تاريخها (بدون الوقت)
    processedMessages.push({
        date: msgDate,
        sender: sender,
        text: text + optionsText
    });
});

// ==========================================
// 4. بناء المخرج النهائي (تجميع العناوين بالأيام)
// ==========================================

// أخذ آخر 10 رسائل فقط
let recentMessages = processedMessages.slice(-10);

let formattedHistory = "";
let currentDateTracker = "";

recentMessages.forEach(m => {
    // إذا تغير التاريخ، نضع التاريخ كعنوان رئيسي
    if (m.date !== currentDateTracker) {
        if (currentDateTracker !== "") formattedHistory += "\n"; // مسافة بين الأيام
        formattedHistory += `${m.date}\n`;
        currentDateTracker = m.date;
    }
    // إضافة الرسالة بدون الوقت
    formattedHistory += `${m.sender}: ${m.text}\n`;
});

// تجميع الملخص النهائي
let finalOutput = `Conversation State Summary:\n`;
finalOutput += `- Failed OTP Attempts: ${failCount}\n`;
finalOutput += `- Successful OTP Activations: ${successCount}\n\n`;

finalOutput += `Recent messages (latest 10):\n`;
finalOutput += formattedHistory.trim();

return [{ 
    json: { 
        ...$input.first().json,
        compact_history: finalOutput,
        latest_customer_message: latestCustomerMessage,
        fail_count: failCount,
        success_count: successCount
    } 
}];

