let currentTime = 'Unavailable';

if (phone) {
  // تنظيف الرقم لضمان وجود علامة + والأرقام فقط
  const cleanPhone = phone.replace(/[^\d+]/g, '');

  // خريطة مفاتيح دول الشرق الأوسط وشمال أفريقيا
  const tzMap = {
    '+966': 'Asia/Riyadh',      // Saudi Arabia
    '+971': 'Asia/Dubai',       // UAE
    '+965': 'Asia/Kuwait',      // Kuwait
    '+974': 'Asia/Qatar',       // Qatar
    '+973': 'Asia/Bahrain',     // Bahrain
    '+968': 'Asia/Muscat',      // Oman
    '+962': 'Asia/Amman',       // Jordan
    '+961': 'Asia/Beirut',      // Lebanon
    '+963': 'Asia/Damascus',    // Syria
    '+964': 'Asia/Baghdad',     // Iraq
    '+967': 'Asia/Aden',        // Yemen
    '+970': 'Asia/Jerusalem',   // Palestine
    '+972': 'Asia/Jerusalem',   // Palestine/Israel
    '+20':  'Africa/Cairo',     // Egypt
    '+212': 'Africa/Casablanca',// Morocco
    '+213': 'Africa/Algiers',   // Algeria
    '+216': 'Africa/Tunis',     // Tunisia
    '+218': 'Africa/Tripoli',   // Libya
    '+249': 'Africa/Khartoum'   // Sudan
  };

  // البحث عن مفتاح الدولة (من 4 أرقام نزولاً إلى 3 أرقام)
  for (let i = 4; i >= 3; i--) {
    const prefix = cleanPhone.substring(0, i);

    if (tzMap[prefix]) {
      // حساب الوقت بناءً على المنطقة الزمنية المكتشفة
      const options = { 
        timeZone: tzMap[prefix], 
        day: '2-digit', month: '2-digit', year: 'numeric', 
        hour: '2-digit', minute: '2-digit', hour12: false 
      };

      const formatter = new Intl.DateTimeFormat('en-GB', options);
      const parts = formatter.formatToParts(new Date());

      const day = parts.find(p => p.type === 'day').value;
      const month = parts.find(p => p.type === 'month').value;
      const year = parts.find(p => p.type === 'year').value;
      const hour = parts.find(p => p.type === 'hour').value;
      const minute = parts.find(p => p.type === 'minute').value;

      currentTime = `${day}/${month}/${year} ${hour}:${minute}`;
      break; // إيقاف الحلقة بمجرد العثور على تطابق
    }
  }
}

// 2. إرجاع البيانات بالشكل الذي يطلبه n8n
return [{
  json: {
    ...$input.first().json, // الاحتفاظ بكل البيانات السابقة
    user_local_time: currentTime // إضافة الوقت الجديد
  }
}];

