// Extract token usage metadata from the AI Agent response and normalize it for analytics.
const aiOutput = $input.first().json;

function findKey(obj, keyToFind) {
  if (obj === null || typeof obj !== 'object') return null;
  if (Object.prototype.hasOwnProperty.call(obj, keyToFind)) return obj[keyToFind];

  for (const key of Object.keys(obj)) {
    const result = findKey(obj[key], keyToFind);
    if (result !== null) return result;
  }

  return null;
}

const usageMeta = findKey(aiOutput, 'usage_metadata') || {};

const inputTokens = Number(
  usageMeta.input_tokens
  || usageMeta.prompt_tokens
  || usageMeta.promptTokenCount
  || usageMeta.promptTokens
  || findKey(aiOutput, 'input_tokens')
  || findKey(aiOutput, 'prompt_tokens')
  || 0
);

const outputTokens = Number(
  usageMeta.output_tokens
  || usageMeta.completion_tokens
  || usageMeta.candidatesTokenCount
  || usageMeta.outputTokens
  || findKey(aiOutput, 'output_tokens')
  || findKey(aiOutput, 'completion_tokens')
  || 0
);

const totalTokens = Number(
  usageMeta.total_tokens
  || usageMeta.totalTokenCount
  || (inputTokens + outputTokens)
  || 0
);

const cacheRead = Number(
  usageMeta.cachedContentTokenCount
  || findKey(aiOutput, 'cache_read')
  || 0
);

return [{
  json: {
    ...aiOutput,
    safe_total_tokens: totalTokens,
    safe_input_tokens: inputTokens,
    safe_output_tokens: outputTokens,
    safe_cache_read: cacheRead,
  }
}];
